  ('dietitian-moex-00786', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '江先生因end-stagerenaldisease入院，其血液生化值如右：BUN100mg/dL、creatinine10.0mg/dL、 potassium6.2mEq/L、phosphorus6.8mg/dL，有關其治療方式的蛋白質每日攝取建議，下列何者 正確？', '["Hemodialysis：0.8～1.0g/kg", "Peritonealdialysis：1.2～1.5g/kg", "Kidneytransplant後4～6週：0.6～0.8g/kg", "Kidneytransplant3個月後：1.3～2.0g/kg"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "45b10eeb9df5", "answer_pdf_sha1": "e6f1e0f87add", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
