  ('dietitian-moex-00792', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟移植病人術後短期的營養照顧目標和飲食建議，下列何者錯誤？', '["蛋白質1.3～2公克／公斤／日", "病人食慾不佳時，應透過全靜脈營養，預防營養不良產生術後併發症", "手術壓力和免疫抑制劑可能提升高血糖風險", "鈉2公克／日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:52+00:00", "source_pdf_sha1": "45b10eeb9df5", "answer_pdf_sha1": "e6f1e0f87add", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
